  ('medical-tech-moex-14813', 'medical-tech', 'medical-tech-moex-099-716b3930', 'sub-medical-tech-07', NULL, 'single_choice', '有關Mycobacterium tuberculosis的培養，下列敘述何者錯誤？', '["痰檢體經NALC-NaOH消化及去污染處理後，再行培養可增加培養的陽性率", "來自於CSF的檢體僅需離心濃縮即可接種培養基，不需要消化去污染的處理", "檢體接種於L-J培養基後必須立即關緊瓶蓋培養，以避免水分散失", "置於二氧化碳培養箱中培養，可促進Mycobacterium tuberculosis的生長"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:00+00:00", "source_pdf_sha1": "3fcb249baa6d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "104", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 62, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
